      "metric_name": "sales_p4w_mg_nation",
      "function": "SUM",
      "column": "relmora_total_mg",
      "group_level": "none"
    }
  ],
  "subqueries": [
    {
      "name": "max_week_end_date_cte",
      "purpose": "Anchor rolling week windows to the latest available week_end_date in the dataset.",
      "logic": "Compute max_week_end_date = MAX(week_end_date) from data_867."
    },
    {
      "name": "distinct_weeks_cte",
      "purpose": "Enumerate distinct week_end_date values up to the max week to reliably pick the most recent distinct weeks.",
      "logic": "Select DISTINCT week_end_date from data_867 where week_end_date <= (select max_week_end_date from max_week_end_date_cte)."
    },
    {
      "name": "r4w_weeks_cte",
      "purpose": "Determine the 4 most recent distinct weeks (R4W).",
      "logic": "From distinct_weeks_cte order by week_end_date DESC and keep the top 4 week_end_date rows."
    },
