    },
    {
      "name": "child_type_combined_cte",
      "purpose": "Combine R4W and P4W totals per child account type and compute growth, using weekly normalization only if the window week counts differ.",
      "logic": "FULL OUTER JOIN r4w_sales_by_child_type_cte and p4w_sales_by_child_type_cte on campus_account_type. Treat missing sales as 0 and missing week_count as 0. If r4w_week_count != p4w_week_count and both counts > 0 then compute r4w_weekly_avg_mg = ROUND(r4w_sales_mg / r4w_week_count, 0) and p4w_weekly_avg_mg = ROUND(p4w_sales_mg / p4w_week_count, 0) else set r4w_weekly_avg_mg = ROUND(r4w_sales_mg, 0) and p4w_weekly_avg_mg = ROUND(p4w_sales_mg, 0). Compute growth_4w_pct_child as: if p4w_weekly_avg_mg = 0 and r4w_weekly_avg_mg > 0 then '100%' else if p4w_weekly_avg_mg = 0 and r4w_weekly_avg_mg = 0 then '0%' else ROUND(((r4w_weekly_avg_mg - p4w_weekly_avg_mg) / p4w_weekly_avg_mg) * 100, 0) || '%'. Also compute abs_change_4w_mg = ROUND(r4w_weekly_avg_mg - p4w_weekly_avg_mg, 0)."
